import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { toast } from 'react-toastify';
import api from '../../utils/api';

const STATUS_FILTERS = [
  { value: '',                label: 'All Events',       icon: '📊', color: 'text-cyan-400',       bg: 'bg-cyan-500/10' },
  { value: 'pending_approval',label: 'Pending Approval', icon: '⏳', color: 'text-amber-400',      bg: 'bg-amber-500/10' },
  { value: 'published',       label: 'Published',        icon: '✅', color: 'text-emerald-400',    bg: 'bg-emerald-500/10' },
  { value: 'rejected',        label: 'Rejected',         icon: '❌', color: 'text-rose-400',       bg: 'bg-rose-500/10' },
  { value: 'completed',       label: 'Completed',        icon: '🏁', color: 'text-purple-400',     bg: 'bg-purple-500/10' },
  { value: 'cancelled',       label: 'Cancelled',        icon: '🚫', color: 'text-slate-400',      bg: 'bg-slate-500/10' },
];

const STATUS_COLOR = {
  pending_approval: 'border-amber-500/30 bg-amber-500/10 text-amber-400',
  published:        'border-emerald-500/30 bg-emerald-500/10 text-emerald-400',
  rejected:         'border-rose-500/30 bg-rose-500/10 text-rose-400',
  completed:        'border-purple-500/30 bg-purple-500/10 text-purple-400',
  cancelled:        'border-slate-500/30 bg-slate-500/10 text-slate-400',
  draft:            'border-slate-500/30 bg-slate-500/10 text-slate-400',
};

const STATUS_LABEL = {
  pending_approval: '⏳ Pending Approval',
  published:        '✅ Published',
  rejected:         '❌ Rejected',
  completed:        '🏁 Completed',
  cancelled:        '🚫 Cancelled',
  draft:            '📝 Draft',
};

const fmt = (d) =>
  d ? new Date(d).toLocaleDateString('en-US', { day: 'numeric', month: 'short', year: 'numeric' }) : '—';

export default function AdminEvents() {
  const [events, setEvents]         = useState([]);
  const [loading, setLoading]       = useState(true);
  const [statusFilter, setStatus]   = useState('');
  const [search, setSearch]         = useState('');

  const fetchAll = async () => {
    setLoading(true);
    try {
      const res = await api.get('/events/all?limit=500');
      setEvents(res.data.data || []);
    } catch {
      toast.error('Failed to load events');
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => { fetchAll(); }, []);

  const approveEvent = async (id, title) => {
    try {
      await api.put(`/events/${id}/approve`);
      toast.success(`"${title}" approved and published!`);
      fetchAll();
    } catch (err) {
      toast.error(err.response?.data?.message || 'Failed to approve');
    }
  };

  const rejectEvent = async (id, title) => {
    const reason = prompt(`Reason for rejecting "${title}":`);
    if (reason === null) return;
    try {
      await api.put(`/events/${id}/reject`, { reason });
      toast.success(`"${title}" rejected`);
      fetchAll();
    } catch {
      toast.error('Failed to reject event');
    }
  };

  const filtered = events.filter(e => {
    const matchesStatus = !statusFilter || e.status === statusFilter;
    const matchesSearch = !search ||
      e.title?.toLowerCase().includes(search.toLowerCase()) ||
      e.community?.name?.toLowerCase().includes(search.toLowerCase()) ||
      e.createdBy?.name?.toLowerCase().includes(search.toLowerCase());
    return matchesStatus && matchesSearch;
  });

  const countFor = (s) => events.filter(e => (!s ? true : e.status === s)).length;

  return (
    <div className="min-h-screen p-6 md:p-10 font-sans text-slate-100 relative overflow-hidden bg-[#020617]">
      {/* Background Orbs */}
      <div className="absolute top-0 right-0 w-[500px] h-[500px] bg-purple-600/10 rounded-full mix-blend-screen filter blur-[120px] animate-blob pointer-events-none" />
      <div className="absolute top-1/2 left-0 w-[600px] h-[600px] bg-cyan-600/10 rounded-full mix-blend-screen filter blur-[150px] animation-delay-4000 animate-blob pointer-events-none" />

      <div className="max-w-7xl mx-auto relative z-10 space-y-10">

        {/* Header */}
        <header className="glass-dark rounded-3xl p-8 border border-white/10 flex flex-col md:flex-row justify-between items-start md:items-center gap-6 shadow-[0_15px_40px_rgba(0,0,0,0.5)] relative overflow-hidden group">
          <div className="absolute inset-0 bg-gradient-to-r from-purple-500/5 via-pink-500/5 to-cyan-500/5 opacity-0 group-hover:opacity-100 transition-opacity duration-700" />

          <div className="relative z-10">
            <h1 className="text-3xl md:text-4xl font-black mb-2 tracking-tight">
              EVENT <span className="text-transparent bg-clip-text bg-gradient-to-r from-purple-400 to-cyan-400">MANAGEMENT</span>
            </h1>
            <div className="flex items-center gap-4 flex-wrap">
              <span className="px-4 py-1.5 rounded-full bg-cyan-500/10 border border-cyan-500/20 text-cyan-400 font-bold text-sm flex items-center gap-2 shadow-[0_0_15px_rgba(6,182,212,0.15)]">
                📅 {events.length} Total Registered Events
              </span>
              {countFor('pending_approval') > 0 && (
                <span className="px-4 py-1.5 rounded-full bg-amber-500/10 border border-amber-500/20 text-amber-500 font-bold text-sm flex items-center gap-2 shadow-[0_0_15px_rgba(245,158,11,0.15)] animate-pulse">
                  ⏳ {countFor('pending_approval')} waiting for review
                </span>
              )}
            </div>
          </div>

          <Link to="/admin" className="relative z-10 glass hover:bg-white/10 px-6 py-3 rounded-full font-bold text-white transition-all hover:-translate-y-1 border border-white/10 flex items-center gap-2 text-sm uppercase tracking-wider">
            ← Dashboard
          </Link>
        </header>

        {/* Stats Grid */}
        <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-5 gap-4">
          {STATUS_FILTERS.slice(1).map(f => (
            <button key={f.value} onClick={() => setStatus(statusFilter === f.value ? '' : f.value)} className={`glass border rounded-2xl p-5 text-center transition-all duration-300 relative overflow-hidden group ${statusFilter === f.value ? 'border-puple-500 shadow-[0_0_20px_rgba(168,85,247,0.3)] bg-white/10' : 'border-white/5 hover:border-white/20 hover:bg-white/5'}`}>
               <div className={`absolute inset-0 bg-gradient-to-t from-black/60 to-transparent pointer-events-none`} />
               <div className="relative z-10 flex flex-col items-center">
                 <span className="text-3xl mb-2 drop-shadow-lg group-hover:scale-110 transition-transform duration-300">{f.icon}</span>
                 <span className={`text-3xl font-black tracking-tight mb-1 ${f.color}`}>{countFor(f.value)}</span>
                 <span className="text-xs font-bold text-slate-400 uppercase tracking-widest">{f.label}</span>
               </div>
            </button>
          ))}
        </div>

        {/* Filters Toolbar */}
        <div className="glass-dark rounded-2xl p-4 md:p-6 border border-white/5 flex flex-col lg:flex-row justify-between items-center gap-6">
          <div className="flex flex-wrap gap-2">
            {STATUS_FILTERS.map(f => (
              <button key={f.value} onClick={() => setStatus(f.value)} className={`px-4 py-2 rounded-xl text-sm font-bold flex items-center gap-2 transition-all border ${statusFilter === f.value ? `bg-white/10 text-white shadow-lg ${f.color.replace('text-', 'border-')}` : 'border-transparent text-slate-400 hover:bg-white/5 hover:text-slate-300'}`}>
                <span className="drop-shadow-sm">{f.icon}</span> {f.label}
                {f.value && (
                  <span className={`px-2 py-0.5 rounded text-[10px] font-black tracking-wider ${statusFilter === f.value ? f.color : 'bg-slate-800 text-slate-300'}`}>
                    {countFor(f.value)}
                  </span>
                )}
              </button>
            ))}
          </div>

          <div className="relative w-full lg:w-96 group">
            <span className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400 group-hover:text-cyan-400 transition-colors">🔍</span>
            <input type="text" placeholder="Search events, communities, organizers..." value={search} onChange={e => setSearch(e.target.value)} className="w-full bg-black/40 border border-white/10 rounded-xl pl-12 pr-10 py-3 text-white focus:outline-none focus:border-cyan-500/50 focus:ring-1 focus:ring-cyan-500/50 transition-all font-medium" />
            {search && (
              <button onClick={() => setSearch('')} className="absolute right-4 top-1/2 -translate-y-1/2 text-slate-500 hover:text-white transition-colors">✕</button>
            )}
          </div>
        </div>

        {/* Action Area */}
        <div className="relative">
          {loading ? (
            <div className="flex flex-col items-center justify-center min-h-[40vh] space-y-4">
              <div className="w-12 h-12 border-4 border-cyan-500/30 border-t-cyan-500 rounded-full animate-spin" />
              <span className="text-cyan-400 font-medium tracking-widest uppercase text-sm animate-pulse">Loading Events...</span>
            </div>
          ) : filtered.length === 0 ? (
            <div className="flex flex-col items-center justify-center text-center p-16 glass-dark rounded-3xl border border-white/5 opacity-80 backdrop-blur-3xl shadow-2xl">
              <span className="text-6xl mb-6 drop-shadow-2xl opacity-50">📅</span>
              <h3 className="text-3xl font-black mb-3 text-white">No results found</h3>
              <p className="text-slate-400 font-medium max-w-md">Try adjusting your filters or search terms. There are currently no events matching this criteria.</p>
              {(search || statusFilter) && (
                 <button onClick={() => { setSearch(''); setStatus(''); }} className="mt-8 px-8 py-3 rounded-full bg-white/10 hover:bg-white/20 font-bold transition-all border border-white/10 text-white border-dashed text-sm tracking-widest uppercase">Clear all filters</button>
              )}
            </div>
          ) : (
            <div className="grid grid-cols-1 xl:grid-cols-2 gap-6">
              {filtered.map(ev => (
                <div key={ev._id} className="glass-dark border border-white/5 rounded-3xl overflow-hidden shadow-2xl hover:shadow-[0_20px_50px_rgba(0,0,0,0.5)] transition-all duration-300 hover:-translate-y-1 group relative flex flex-col">
                  {/* Decorative Side Ribbon */}
                  <div className={`absolute left-0 top-0 bottom-0 w-1.5 opacity-50 group-hover:opacity-100 transition-opacity ${STATUS_COLOR[ev.status]?.split(' ')[1] || 'bg-slate-500'}`} />

                  <div className="p-6 md:p-8 flex flex-col sm:flex-row gap-6 items-start h-full">
                    {/* Icon Bubble */}
                    <div className={`w-16 h-16 rounded-2xl flex items-center justify-center text-3xl shrink-0 shadow-lg border relative overflow-hidden ${STATUS_COLOR[ev.status] || 'border-slate-500/30 bg-slate-500/10 text-slate-400'}`}>
                      <div className="absolute inset-0 bg-gradient-to-br from-white/10 to-transparent pointer-events-none" />
                      📅
                    </div>

                    {/* Content */}
                    <div className="flex-1 min-w-0 flex flex-col h-full w-full">
                      <div className="flex justify-between items-start gap-4 mb-3 flex-wrap">
                        <h3 className="font-bold text-xl md:text-2xl text-white group-hover:text-cyan-400 transition-colors leading-tight line-clamp-2">{ev.title}</h3>
                        <span className={`px-3 py-1 font-black uppercase text-[10px] tracking-wider rounded border shadow-md shrink-0 flex items-center gap-1.5 ${STATUS_COLOR[ev.status] || 'border-slate-500/30 bg-slate-500/10 text-slate-400'}`}>
                          {STATUS_LABEL[ev.status] || ev.status}
                        </span>
                      </div>

                      <div className="flex flex-wrap items-center gap-3 mb-4">
                        <span className="px-2.5 py-1 text-xs font-bold rounded-md bg-purple-500/10 border border-purple-500/20 text-purple-400 shrink-0 capitalize">{ev.category}</span>
                        <span className="flex items-center gap-1.5 text-xs font-medium text-cyan-400 bg-black/40 px-2.5 py-1 rounded-md border border-cyan-500/10 truncate max-w-full">
                          🏛️ {ev.community?.name || 'Unknown Community'}
                        </span>
                      </div>

                      <p className="text-sm text-slate-400 mb-6 line-clamp-3 leading-relaxed">
                        {ev.description || 'No description provided.'}
                      </p>

                      {ev.status === 'rejected' && ev.rejectionReason && (
                        <div className="mt-3 mb-5 p-3 rounded-lg bg-rose-500/10 border border-rose-500/20 text-rose-300 text-sm flex gap-3 relative">
                           <span className="text-xl">⚠️</span>
                           <span className="flex-1"><strong className="text-rose-400 uppercase tracking-widest text-[10px] block mb-0.5">Rejection Reason</strong> {ev.rejectionReason}</span>
                        </div>
                      )}

                      <div className="mt-auto pt-4 border-t border-white/5 flex flex-col md:flex-row justify-between items-start md:items-end gap-6">
                        {/* Event Tags Meta */}
                        <div className="flex flex-wrap gap-x-6 gap-y-3">
                           <div className="flex flex-col">
                             <span className="text-[10px] font-bold text-slate-500 uppercase tracking-widest mb-1">Date</span>
                             <span className="text-xs font-medium text-slate-300 flex items-center gap-1.5"><span className="text-cyan-400 opacity-70">📅</span>{fmt(ev.startDate)}</span>
                           </div>
                           {ev.venue && (
                             <div className="flex flex-col">
                               <span className="text-[10px] font-bold text-slate-500 uppercase tracking-widest mb-1">Location</span>
                               <span className="text-xs font-medium text-slate-300 flex items-center gap-1.5 max-w-[120px] truncate"><span className="text-purple-400 opacity-70">📍</span>{ev.venue}</span>
                             </div>
                           )}
                           <div className="flex flex-col">
                             <span className="text-[10px] font-bold text-slate-500 uppercase tracking-widest mb-1">Organizer</span>
                             <span className="text-xs font-medium text-slate-300 flex items-center gap-1.5 max-w-[120px] truncate"><span className="text-pink-400 opacity-70">👤</span>{ev.createdBy?.name || '—'}</span>
                           </div>
                           {ev.isVirtual && (
                             <div className="flex flex-col">
                               <span className="text-[10px] font-bold text-emerald-500 uppercase tracking-widest mb-1">Format</span>
                               <span className="text-xs font-bold text-emerald-400 flex items-center gap-1.5">💻 Virtual</span>
                             </div>
                           )}
                        </div>

                        {/* Approvals */}
                        <div className="flex gap-3 w-full md:w-auto shrink-0 mt-2 md:mt-0">
                          {ev.status === 'pending_approval' && (
                            <>
                              <button onClick={() => approveEvent(ev._id, ev.title)} className="flex-1 md:flex-none py-2.5 px-5 rounded-xl bg-gradient-to-r from-emerald-500 to-emerald-600 font-bold text-xs uppercase tracking-widest text-white hover:shadow-[0_0_20px_rgba(16,185,129,0.4)] hover:-translate-y-0.5 transition-all flex justify-center items-center gap-2">✓ Publish</button>
                              <button onClick={() => rejectEvent(ev._id, ev.title)} className="flex-1 md:flex-none py-2.5 px-5 rounded-xl bg-slate-900 border border-rose-500/30 text-rose-400 font-bold text-xs uppercase tracking-widest hover:border-rose-500 hover:bg-rose-500/10 hover:-translate-y-0.5 transition-all flex justify-center items-center gap-2">✗ Decline</button>
                            </>
                          )}
                          {ev.status === 'rejected' && (
                            <button onClick={() => approveEvent(ev._id, ev.title)} className="w-full md:w-auto py-2 px-6 rounded-lg bg-emerald-500/10 border border-emerald-500/20 font-bold text-xs uppercase tracking-widest text-emerald-400 hover:border-emerald-500/40 hover:bg-emerald-500/20 hover:-translate-y-0.5 transition-all flex justify-center items-center gap-2">⟲ Approve Anyway</button>
                          )}
                        </div>
                      </div>
                    </div>
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>
      </div>
    </div>
  );
}
